  "q1_people_count_and_visibility": {
    "people": [
      {
        "name": "田中健一（KENICHI_MAIN）",
        "role_in_shot": "在家中从久坐后的不安转向卧室抽屉，发现彩花留下的浅粉色丝巾和小樱照片；听到彩花记忆低语后被门外敲门声打断，放下丝巾走向门口。",
        "visibility": "onscreen_visible",
        "evidence": "“健一在家中的沙发上坐了许久……他起身去卧室，打开抽屉……健一盯着照片，手指摩挲着边缘……他放下丝巾，走向门口。”"
      },
      {
        "name": "佐藤樱子（SAKURA_CHILD，照片中）",
        "role_in_shot": "作为抽屉深处照片上的十四岁女孩出现，是健一确认“小樱”真实存在的视觉线索。",
        "visibility": "onscreen_visible",
        "evidence": "“抽屉深处，还有一张照片。小樱，一个十四岁的女孩……她穿着校服，站在公园里，笑容浅浅。”"
      },
      {
        "name": "佐藤彩花（AYAKA_VICTIM，记忆声音）",
        "role_in_shot": "不以实体出现，只在健一触碰彩花留下的丝巾时，以主观记忆低语重复“守护小樱”。",
        "visibility": "offscreen_voice",
        "evidence": "“耳边仿佛又响起她的低语：‘守护小樱。’”"
      },
      {
        "name": "门外未知敲门者/可能的邻居",
        "role_in_shot": "只由公寓门外忽然响起的敲门声和健一的猜测构成悬念，身份未确认，不可见也无对白。",
        "visibility": "mentioned_only",
        "evidence": "“门外忽然响起敲门声……或许是邻居，或许是……”"
      }
    ],
    "onscreen_visible_count": 2,
    "offscreen_voice_count": 1,
    "mentioned_only_count": 1
